mapper.insert:
	/*
		 SQL ID : OrgCfgDAO.insert
		 설  명 : 기관 설정 정보의 정보 등록
 	*/
	INSERT INTO TB_ORG_CFG (
	       ORG_ID
	     , STNG_CD
	     , STNG_CTGRCD
	     , STNGNM
	     , STNG_VL
	     , STNG_EXPLN
	     , USEYN
	     , RGTR_ID
	     , FRST_INQ_DTTM
	     , MDFR_ID
	     , MOD_DTTM
	) VALUES (
	       #{orgId}
	     , #{cfgCd}
	     , #{cfgCtgrCd}
	     , #{cfgNm}
	     , #{cfgVal}
	     , #{cfgDesc}
	     , #{useYn}
	     , #{rgtrId}
	     , FN_DTTM()
	     , #{mdfrId}
	     , FN_DTTM()
	)

mapper.update:
	/*
		 SQL ID : OrgCfgDAO.update
		 설  명 : 기관 설정 정보의 정보 수정
 	*/
	UPDATE TB_ORG_CFG
	   SET MOD_DTTM = FN_DTTM()
	   	 , MDFR_ID = #{mdfrId}

	   	 , ORG_ID = #{orgId}


	   	 , STNGNM = #{cfgNm}


	     , STNG_VL = #{cfgVal}


	     , STNG_EXPLN = #{cfgDesc}


	     , USEYN = #{useYn}

	 WHERE STNG_CTGRCD = #{cfgCtgrCd}
	   AND STNG_CD = #{cfgCd}
	   AND ORG_ID = #{orgId}

mapper.delete:
	/*
		 SQL ID : OrgCfgDAO.delete
		 설  명 : 기관 설정 정보의 정보 삭제
 	*/	
	DELETE FROM TB_ORG_CFG
	 WHERE STNG_CTGRCD = #{cfgCtgrCd}
	   AND STNG_CD = #{cfgCd}
	   AND ORG_ID = #{orgId}

	/*
		 SQL ID : OrgCfgDAO.deleteAll
